INSERT INTO organisations (name, slug, contactEmail, createdByUserId, createdAt, updatedAt)
VALUES ('Orchid Dermatology Group', 'orchid-dermatology', 'dave@pursuitpathways.com', 1, NOW(), NOW());

SET @orgId = LAST_INSERT_ID();

INSERT INTO org_members (orgId, userId, orgRole, invitedAt, joinedAt)
VALUES (@orgId, 1, 'org_admin', NOW(), NOW());

UPDATE facilities SET orgId = @orgId WHERE id = 1;
UPDATE audits SET orgId = @orgId WHERE facilityId = 1;

SELECT o.id, o.name, o.slug, om.orgRole, u.name AS memberName
FROM organisations o
JOIN org_members om ON om.orgId = o.id
JOIN users u ON u.id = om.userId
WHERE o.slug = 'orchid-dermatology';

